import { useEffect, useState } from "react";
import { supabase } from "@/integrations/supabase/client";

export function useSiteSettings(id: string) {
  const [data, setData] = useState<any>(null);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    const fetch = async () => {
      const { data: row } = await supabase
        .from("site_settings")
        .select("value")
        .eq("id", id)
        .single();
      if (row) setData(row.value);
      setIsLoading(false);
    };
    fetch();
  }, [id]);

  return { data, isLoading };
}

export async function updateSiteSettings(id: string, value: any) {
  const { error } = await supabase
    .from("site_settings")
    .update({ value, updated_at: new Date().toISOString() })
    .eq("id", id);
  if (error) throw new Error(error.message);
}

import { createContext, useContext, useEffect, useMemo, useState, ReactNode } from "react";
import { dict, LOCALES, DEFAULT_LOCALE, type Locale } from "./translations";

type Ctx = {
  locale: Locale;
  setLocale: (l: Locale) => void;
  t: typeof dict.en;
  dir: "ltr" | "rtl";
  formatPrice: (n: number) => string;
};

const I18nCtx = createContext<Ctx | null>(null);

export function I18nProvider({ children }: { children: ReactNode }) {
  const [locale, setLocaleState] = useState<Locale>(() => {
    if (typeof window === "undefined") return DEFAULT_LOCALE;
    const saved = localStorage.getItem("locale") as Locale | null;
    return saved && LOCALES.includes(saved) ? saved : DEFAULT_LOCALE;
  });

  const dir: "ltr" | "rtl" = locale === "ar" ? "rtl" : "ltr";

  useEffect(() => {
    document.documentElement.lang = locale;
    document.documentElement.dir = dir;
    localStorage.setItem("locale", locale);
  }, [locale, dir]);

  const value = useMemo<Ctx>(() => ({
    locale,
    setLocale: setLocaleState,
    t: dict[locale],
    dir,
    formatPrice: (n: number) => {
      const fmt = new Intl.NumberFormat(locale === "ar" ? "ar-SA" : locale === "tr" ? "tr-TR" : "en-US", {
        style: "currency",
        currency: "TRY",
        maximumFractionDigits: 0,
      });
      return fmt.format(n);
    },
  }), [locale, dir]);

  return <I18nCtx.Provider value={value}>{children}</I18nCtx.Provider>;
}

export function useI18n() {
  const ctx = useContext(I18nCtx);
  if (!ctx) throw new Error("useI18n must be inside I18nProvider");
  return ctx;
}

export function localizedField<T extends Record<string, any>>(
  obj: T,
  base: string,
  locale: Locale,
): string {
  return obj[`${base}_${locale}`] ?? obj[`${base}_en`] ?? "";
}

/**
 * Scalable API Client for backend communications.
 * This architecture separates UI logic from API communication.
 */

const BACKEND_API_URL = import.meta.env.VITE_BACKEND_API_URL || '';

export interface ApiResponse<T = any> {
  success: boolean;
  data?: T;
  error?: string;
}

export const apiClient = {
  /**
   * General purpose fetch wrapper for backend calls
   */
  async request<T>(endpoint: string, options: RequestInit = {}): Promise<ApiResponse<T>> {
    try {
      // In a real production app, we would include the auth token here
      // const session = await supabase.auth.getSession();
      // const token = session.data.session?.access_token;

      const response = await fetch(`${BACKEND_API_URL}${endpoint}`, {
        ...options,
        headers: {
          'Content-Type': 'application/json',
          // 'Authorization': `Bearer ${token}`,
          ...options.headers,
        },
      });

      if (!response.ok) {
        const errorData = await response.json().catch(() => ({}));
        return { 
          success: false, 
          error: errorData.message || `Request failed with status ${response.status}` 
        };
      }

      const data = await response.json();
      return { success: true, data };
    } catch (error: any) {
      console.error(`API Error [${endpoint}]:`, error);
      return { success: false, error: error.message || 'An unexpected error occurred' };
    }
  },

  /**
   * Request email notification (backend handles actual sending)
   */
  async sendNotificationRequest(type: 'order_update' | 'promotion' | 'account_alert', payload: any): Promise<ApiResponse> {
    // Backend responsible for connecting to Resend/Brevo/SMTP
    return this.request('/api/notifications/send', {
      method: 'POST',
      body: JSON.stringify({ type, payload }),
    });
  }
};

